const input = $input.first().json;
const msg = (input.chatInput || input.body?.user_message_request || '').toLowerCase();
const original = input.chatInput || input.body?.user_message_request || '';

// BRAINSTORM ops checked first — story planning, outline expansion, character development
const isBrainstormOp = /\b(brainstorm|expand.{0,25}outline|add.{0,15}(more\s+)?chapter|develop.{0,20}character|revise.{0,20}(outline|story\s+arc)|rework.{0,20}(outline|story)|outline\s+(a|the|my|this)\s+\w|plan\s+(a|the|my)\s+(novel|book|story)|create\s+(a|the|my)\s+(outline|book))/.test(msg);

// LIBRARY ops — content status management only
const isLibraryOp = /\b(approve|unschedule|unpublish|publish|reject|schedule|list\s+(all|draft|published|scheduled|approved|rejected)|content\s+librar|my\s+(draft|post|content|article|newsletter|chapter|stor)|show\s+(me\s+)?(my|what|all)|what.{0,20}(written|published|draft|created)|show\s+all|see\s+all|all\s+content|all\s+(my\s+)?(posts?|draft|items?|articles?)|remove.{0,20}(schedule|publish)|cancel.{0,20}schedule|version\s+histor|list\s+version|get\s+version|show.{0,15}version|version.{0,10}(this|that|it))/.test(msg);

// WRITING ops — trigger writing sub-workflows
const isWritingOp = /\b(write\s+(a|the|my|an)\s+(blog|newsletter|short\s+stor|chapter|article)|write\s+chapter)/.test(msg);

if (isBrainstormOp) {
  return [{ json: { ...input, chatInput: original + ' [MANDATORY: Call brainstorm_story tool RIGHT NOW with all project details from my message. Do NOT generate any outline, character profiles, or story content in chat. Do not write any response before calling the tool.]' } }];
}
if (isLibraryOp) {
  return [{ json: { ...input, chatInput: original + ' [MANDATORY: Call manage_library with content_title from my message right now. Do not respond with any text before calling the tool.]' } }];
}
if (isWritingOp) {
  return [{ json: { ...input, chatInput: original + ' [MANDATORY: Call the appropriate writing tool (write_blog_post, write_newsletter, write_short_story, or write_chapter) right now. Do NOT write content in chat. Do not respond before calling the tool.]' } }];
}

return [{ json: input }];
